create table estudiante (necesidad_especial boolean not null, no_eliminar boolean not null, convocatoria_id bigint not null, id bigint generated by default as identity, instituto_id bigint not null, sede_id bigint, apellido1 varchar(255) not null, apellido2 varchar(255), codigo_pegatina varchar(255) not null, dni varchar(255) not null, email varchar(255), nombre varchar(255) not null, telefono varchar(255), primary key (id), constraint uk_estudiante_dni_convocatoria unique (dni, convocatoria_id), constraint uk_estudiante_pegatina_convocatoria unique (codigo_pegatina, convocatoria_id));
create table estudiante_materia (estudiante_id bigint not null, materia_id bigint not null);
create table instituto (codigo_postal integer, id bigint generated by default as identity, direccion1 varchar(255), direccion2 varchar(255), localidad varchar(255), nombre varchar(255) not null, pais varchar(255), primary key (id));
alter table if exists estudiante_materia add constraint FKa0l31tvll0ekfrq7w2a16v4nn foreign key (estudiante_id) references estudiante;
